import { useNavigate } from "react-router-dom";

import MainBtns from "../Buttons/MainBtns";

import searchIcon from "../../Files/Search.png";
import cartIcon from "../../Files/Shopping cart.png";
import config from "../../config.json";

function Header() {
  const navigate = useNavigate();
  const name = config.nameOfSite;
  return (
    <header className="header">
      <div className="logo">{name}</div>
      <div className="search-bar">
        <img src={searchIcon} alt="search" className="search-icon" />
        <input type="text" placeholder="Поиск" className="search-input" />
      </div>
      <div className="actions">
        <button className="icon-btns shopping-cart-btn">
          <img src={cartIcon} alt="shopping-cart" className="icons shopping-cart-icon" />
        </button>
        <MainBtns Text={"Войти"} FontSize={14} Style={"null-btn"} Onclick={navigate("/login")}/>
        <MainBtns Text={"Регистрация"} FontSize={14} Style={"purple-btn"}/>
      </div>
    </header>
  );
}

export default Header;
